// src/context/SkillsContext.js

import React,
{
 createContext,
 useContext,
 useEffect,
 useState
}
from "react";

import { useAuth }
from "./AuthContext";

import {
 getSkills,
 addSkill,
 updateSkill,
 deleteSkill,
 getAnalyses,
 getActivity
}
from "../services/userService";


const SkillsContext =
createContext(null);


export function useSkills(){

 return useContext(
  SkillsContext
 );

}


export function SkillsProvider(
 { children }
){

 const { user } =
 useAuth();


 const [skills,setSkills] =
 useState([]);

 const [analyses,setAnalyses] =
 useState([]);

 const [activity,setActivity] =
 useState([]);

 const [streak,setStreak] =
 useState(0);

 const [loadingData,setLoadingData] =
 useState(true);



 useEffect(()=>{

 async function loadData(){

  if(!user) return;

  try{

   const s =
   await getSkills(
    user.uid
   );

   const a =
   await getAnalyses(
    user.uid
   );

   const act =
   await getActivity(
    user.uid
   );


   setSkills(s || []);
   setAnalyses(a || []);
   setActivity(act || []);


   setStreak(
    act?.length || 0
   );

  }
  catch(err){

   console.log(err);

  }

  setLoadingData(false);

 }

 loadData();

 },[user]);



 async function createSkill(skill){

  const id =
  await addSkill(
   user.uid,
   skill
  );

  setSkills(prev=>[

   ...prev,
   { id,...skill }

  ]);

 }



 async function editSkill(id,data){

  await updateSkill(
   user.uid,
   id,
   data
  );

  setSkills(prev=>

   prev.map(s=>

    s.id===id ?

    { ...s,...data }

    :

    s

   )

  );

 }



 async function removeSkill(id){

  await deleteSkill(
   user.uid,
   id
  );

  setSkills(prev=>

   prev.filter(
    s=>s.id!==id
   )

  );

 }



 // safe calculated values

 const avgLevel =
 skills.length>0

 ? Math.round(

 skills.reduce(
  (a,s)=>a+(s.level||0),
  0
 )

 /skills.length

 )

 : 0;



 const criticalGaps =
 analyses?.flatMap(
  a=>a.gaps||[]
 ) || [];



 const value={

  skills,
  analyses,
  activity,
  streak,
  avgLevel,
  criticalGaps,
  loadingData,

  createSkill,
  editSkill,
  removeSkill

 };


 return(

 <SkillsContext.Provider
 value={value}>

 {children}

 </SkillsContext.Provider>

 );

}
